955		// second path reusing it can be rejected at LOAD naming both conflicting paths.
956		// The multipath bind Opens each path on (source_addr, listen_port), so two paths
957		// sharing a source_addr collide EADDRINUSE at the second ListenUDP (and on every
958		// re-Open after Down/Up, since the engine passes the fixed port back) — a
959		// misconfiguration that must fail fast at load, not at bring-up (defect D10).
960		seenSrc := make(map[netip.Addr]string, len(c.Paths))
961		for i, p := range c.Paths {
962			if p.Name == "" {
963				return fmt.Errorf("path %d: name is required", i)
964			}
965			if _, dup := seen[p.Name]; dup {
966				return fmt.Errorf("duplicate path name %q", p.Name)
967			}
968			seen[p.Name] = struct{}{}
969			if !p.SourceAddr.IsValid() {
970				return fmt.Errorf("path %q: source_addr is required", p.Name)
971			}
972			// Compare the UNMAPPED form: "192.0.2.10" (Is4) and "::ffff:192.0.2.10"
973			// (Is4In6) are distinct under netip == yet bind the identical v4 socket, so
974			// the two spellings must collide in the guard exactly as they do at bind.
975			src := p.SourceAddr.Unmap()
976			if prev, dup := seenSrc[src]; dup {
977				return fmt.Errorf("paths %q and %q share source_addr %s; each path must bind a distinct source address (a shared source collides EADDRINUSE at the second bind)", prev, p.Name, p.SourceAddr)
978			}
979			seenSrc[src] = p.Name
980		}
981		if !c.WireGuard.PrivateKey.IsSet() {
982			return errors.New("wireguard.private_key is required")
